class ProductionSystem:
    def __init__(self):
        self.rules = []  # List of (conditions, action) tuples
        self.working_memory = set()  # Current facts

    def add_rule(self, conditions, action):
        self.rules.append((conditions, action))

    def forward_chain(self):
        while True:
            applicable_rules = []
            # MATCH: Find rules whose conditions are satisfied
            for i, (conditions, action) in enumerate(self.rules):
                if all(cond in self.working_memory for cond in conditions):
                    applicable_rules.append((i, action))

            # If no applicable rules, stop
            if not applicable_rules:
                break

            # RESOLVE: Select first applicable rule (simple conflict resolution)
            selected_idx, action = applicable_rules[0]

            # ACT: Execute the rule
            print(f"Firing rule {selected_idx}: {action}")
            if action not in self.working_memory:
                self.working_memory.add(action)
            else:
                break

        return self.working_memory

# Example usage
ps = ProductionSystem()
ps.add_rule(('fever', 'cough'), 'influenza')
ps.add_rule(('influenza', 'fatigue'), 'serious_flu')
ps.working_memory = {'fever', 'cough'}
result = ps.forward_chain()
print("Final facts:", result)
